-- EAGV trainer module schema patch
-- Safe to rerun: creates missing tables, constraints, columns and indexes without dropping existing structures.
-- Compatibility notes:
--   * members.id already uses UUID in the current schema.
--   * users.id already uses INTEGER in the current schema, so trainer/user foreign keys keep INTEGER.
--   * physical_assessments already exists with INTEGER primary key; this script extends it instead of replacing it.
--   * UUID primary keys in new tables are designed to be generated by the application layer
--     (Prisma, EF Core, .NET APIs, FastAPI), avoiding a hard dependency on database UUID extensions.

BEGIN;

-- ---------------------------------------------------------------------------
-- ROOT TABLES
-- ---------------------------------------------------------------------------

CREATE TABLE IF NOT EXISTS public.trainer_profiles (
    id UUID PRIMARY KEY,
    user_id INTEGER NOT NULL,
    specialty VARCHAR(120),
    cref_registration VARCHAR(80),
    bio TEXT,
    experience_years INTEGER,
    instagram_url TEXT,
    profile_photo_url TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.trainer_profiles ADD COLUMN IF NOT EXISTS user_id INTEGER;
ALTER TABLE public.trainer_profiles ADD COLUMN IF NOT EXISTS specialty VARCHAR(120);
ALTER TABLE public.trainer_profiles ADD COLUMN IF NOT EXISTS cref_registration VARCHAR(80);
ALTER TABLE public.trainer_profiles ADD COLUMN IF NOT EXISTS bio TEXT;
ALTER TABLE public.trainer_profiles ADD COLUMN IF NOT EXISTS experience_years INTEGER;
ALTER TABLE public.trainer_profiles ADD COLUMN IF NOT EXISTS instagram_url TEXT;
ALTER TABLE public.trainer_profiles ADD COLUMN IF NOT EXISTS profile_photo_url TEXT;
ALTER TABLE public.trainer_profiles ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ DEFAULT now();
ALTER TABLE public.trainer_profiles ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ DEFAULT now();

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'fk_trainer_profiles_user'
          AND conrelid = 'public.trainer_profiles'::regclass
    ) THEN
        ALTER TABLE public.trainer_profiles
            ADD CONSTRAINT fk_trainer_profiles_user
            FOREIGN KEY (user_id) REFERENCES public.users(id) ON DELETE CASCADE;
    END IF;
END
$$;

CREATE UNIQUE INDEX IF NOT EXISTS uq_trainer_profiles_user_id
    ON public.trainer_profiles (user_id);

COMMENT ON TABLE public.trainer_profiles IS 'Profile metadata for personal trainers linked to system users.';
COMMENT ON COLUMN public.trainer_profiles.user_id IS 'FK to users(id); users.id is INTEGER in the current schema.';

CREATE TABLE IF NOT EXISTS public.exercise_library (
    id UUID PRIMARY KEY,
    name VARCHAR(160) NOT NULL,
    muscle_group VARCHAR(120),
    exercise_type VARCHAR(80),
    equipment VARCHAR(120),
    difficulty_level VARCHAR(80),
    instructions TEXT,
    video_url TEXT,
    image_url TEXT,
    created_by INTEGER,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS name VARCHAR(160);
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS muscle_group VARCHAR(120);
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS exercise_type VARCHAR(80);
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS equipment VARCHAR(120);
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS difficulty_level VARCHAR(80);
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS instructions TEXT;
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS video_url TEXT;
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS image_url TEXT;
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS created_by INTEGER;
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ DEFAULT now();
ALTER TABLE public.exercise_library ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ DEFAULT now();

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'fk_exercise_library_created_by'
          AND conrelid = 'public.exercise_library'::regclass
    ) THEN
        ALTER TABLE public.exercise_library
            ADD CONSTRAINT fk_exercise_library_created_by
            FOREIGN KEY (created_by) REFERENCES public.users(id) ON DELETE SET NULL;
    END IF;
END
$$;

CREATE INDEX IF NOT EXISTS ix_exercise_library_name
    ON public.exercise_library (name);

CREATE INDEX IF NOT EXISTS ix_exercise_library_muscle_group
    ON public.exercise_library (muscle_group);

CREATE INDEX IF NOT EXISTS ix_exercise_library_exercise_type
    ON public.exercise_library (exercise_type);

COMMENT ON TABLE public.exercise_library IS 'Reusable exercise catalog for trainer workflows, mobile sync and AI recommendations.';
COMMENT ON COLUMN public.exercise_library.instructions IS 'Free-text instructions designed to support trainer notes and future AI assistance.';

