ALTER TABLE public.physical_assessments ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ DEFAULT now();

UPDATE public.physical_assessments
SET posture_analysis = COALESCE(posture_analysis, posture_notes)
WHERE posture_analysis IS NULL AND posture_notes IS NOT NULL;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'fk_physical_assessments_trainer'
          AND conrelid = 'public.physical_assessments'::regclass
    ) THEN
        ALTER TABLE public.physical_assessments
            ADD CONSTRAINT fk_physical_assessments_trainer
            FOREIGN KEY (trainer_id) REFERENCES public.users(id) ON DELETE RESTRICT;
    END IF;
END
$$;

