    ON public.physical_assessments (trainer_id);

CREATE INDEX IF NOT EXISTS ix_physical_assessments_assessment_date
    ON public.physical_assessments (assessment_date);

COMMENT ON TABLE public.physical_assessments IS 'Existing table extended for trainer workflows without breaking the current integer primary key.';
COMMENT ON COLUMN public.physical_assessments.posture_analysis IS 'Preferred API field; posture_notes remains available for backward compatibility.';

