ALTER TABLE public.member_workout_history ADD COLUMN IF NOT EXISTS calories_burned NUMERIC(10, 2);
ALTER TABLE public.member_workout_history ADD COLUMN IF NOT EXISTS perceived_effort VARCHAR(80);
ALTER TABLE public.member_workout_history ADD COLUMN IF NOT EXISTS notes TEXT;
ALTER TABLE public.member_workout_history ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ DEFAULT now();

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'fk_member_workout_history_member'
          AND conrelid = 'public.member_workout_history'::regclass
    ) THEN
        ALTER TABLE public.member_workout_history
            ADD CONSTRAINT fk_member_workout_history_member
            FOREIGN KEY (member_id) REFERENCES public.members(id) ON DELETE CASCADE;
    END IF;
END
$$;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'fk_member_workout_history_plan'
          AND conrelid = 'public.member_workout_history'::regclass
    ) THEN
        ALTER TABLE public.member_workout_history
            ADD CONSTRAINT fk_member_workout_history_plan
            FOREIGN KEY (workout_plan_id) REFERENCES public.workout_plans(id) ON DELETE CASCADE;
    END IF;
END
$$;

CREATE INDEX IF NOT EXISTS ix_member_workout_history_member_id
    ON public.member_workout_history (member_id);

CREATE INDEX IF NOT EXISTS ix_member_workout_history_workout_plan_id
    ON public.member_workout_history (workout_plan_id);

CREATE INDEX IF NOT EXISTS ix_member_workout_history_completed_at
    ON public.member_workout_history (completed_at DESC);

CREATE TABLE IF NOT EXISTS public.exercise_progress (
    id UUID PRIMARY KEY,
    member_id UUID NOT NULL,
    exercise_id UUID NOT NULL,
    max_weight NUMERIC(10, 2),
    repetitions INTEGER,
    execution_notes TEXT,
    recorded_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.exercise_progress ADD COLUMN IF NOT EXISTS member_id UUID;
ALTER TABLE public.exercise_progress ADD COLUMN IF NOT EXISTS exercise_id UUID;
ALTER TABLE public.exercise_progress ADD COLUMN IF NOT EXISTS max_weight NUMERIC(10, 2);
ALTER TABLE public.exercise_progress ADD COLUMN IF NOT EXISTS repetitions INTEGER;
ALTER TABLE public.exercise_progress ADD COLUMN IF NOT EXISTS execution_notes TEXT;
ALTER TABLE public.exercise_progress ADD COLUMN IF NOT EXISTS recorded_at TIMESTAMPTZ DEFAULT now();
ALTER TABLE public.exercise_progress ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ DEFAULT now();

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'fk_exercise_progress_member'
          AND conrelid = 'public.exercise_progress'::regclass
    ) THEN
        ALTER TABLE public.exercise_progress
            ADD CONSTRAINT fk_exercise_progress_member
            FOREIGN KEY (member_id) REFERENCES public.members(id) ON DELETE CASCADE;
    END IF;
END
$$;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'fk_exercise_progress_exercise'
          AND conrelid = 'public.exercise_progress'::regclass
    ) THEN
        ALTER TABLE public.exercise_progress
            ADD CONSTRAINT fk_exercise_progress_exercise
            FOREIGN KEY (exercise_id) REFERENCES public.exercise_library(id) ON DELETE CASCADE;
    END IF;
END
$$;

CREATE INDEX IF NOT EXISTS ix_exercise_progress_member_id
    ON public.exercise_progress (member_id);

CREATE INDEX IF NOT EXISTS ix_exercise_progress_exercise_id
    ON public.exercise_progress (exercise_id);

CREATE INDEX IF NOT EXISTS ix_exercise_progress_recorded_at
    ON public.exercise_progress (recorded_at DESC);

CREATE INDEX IF NOT EXISTS ix_exercise_progress_member_exercise_recorded
    ON public.exercise_progress (member_id, exercise_id, recorded_at DESC);

COMMENT ON TABLE public.exercise_progress IS 'Performance snapshots intended for progress charts, mobile sync and AI training suggestions.';

COMMIT;